<?php require_once 'config.php'; require_auth(); $q=$_GET['q']??''; $st=db()->prepare('SELECT * FROM clients WHERE name LIKE ? OR phone LIKE ? OR dni LIKE ? ORDER BY created_at DESC'); $like="%$q%"; $st->execute([$like,$like,$like]); $rows=$st->fetchAll(); include 'partials/header.php'; ?>
<section class="card"><h1>Clientes</h1><form><input name="q" value="<?=h($q)?>" placeholder="Buscar cliente, teléfono o DNI"></form><table><tr><th>Cliente</th><th>Contacto</th><th>Notas</th></tr><?php foreach($rows as $r):?><tr><td><b><?=h($r['name'])?></b><br><small class="muted">DNI <?=h($r['dni'])?></small></td><td><?=h($r['phone'])?><br><?=h($r['email'])?></td><td><?=h($r['notes'])?></td></tr><?php endforeach;?></table></section><?php include 'partials/footer.php'; ?>
